<?php namespace App\Http\Middleware; use App\Services\RBAC\PermissionService; use Closure; use Illuminate\Http\Request; class CheckPermission { public function __construct(private PermissionService $permService) {} public function handle(Request $req, Closure $next, $perm) { if (!$this->permService->hasPermission(auth()->user(), $perm)) return response()->json(['error' => 'Forbidden'], 403); return $next($req); } }
